const root = $input.first().json;

const envelope = root.body || {};
const data = envelope.data || {};
const message = data.message || {};
const key = data.key || {};

// ---------- TEXT ----------
const conversation = message.conversation || null;
const extendedText = message.extendedTextMessage?.text || null;
const imageCaption = message.imageMessage?.caption || null;
const documentCaption = message.documentMessage?.caption || null;

const textContent =
  conversation ||
  extendedText ||
  imageCaption ||
  documentCaption ||
  null;

const hasText = !!textContent;

// ---------- IMAGE ----------
const imageMessage =
  message.imageMessage ||
  message?.viewOnceMessage?.message?.imageMessage ||
  message?.ephemeralMessage?.message?.imageMessage ||
  null;

const hasImage = !!imageMessage;
const resolvedImageCaption = imageMessage?.caption || '';

// ---------- PDF ----------
const documentMessage =
  message.documentMessage ||
  message?.viewOnceMessage?.message?.documentMessage ||
  message?.ephemeralMessage?.message?.documentMessage ||
  null;

const mimeType = documentMessage?.mimetype?.toLowerCase() || '';
const fileName = documentMessage?.fileName?.toLowerCase() || '';

const hasPdf = !!(
  documentMessage &&
  (mimeType.includes('pdf') || fileName.endsWith('.pdf'))
);

// ---------- JOB ID ----------
const jobId =
  'job_' + Date.now() + '_' + Math.random().toString(36).substring(2, 11);

// ---------- SENDER ----------
const senderJid = key.remoteJid || envelope.sender || 'unknown';

return [{
  json: {
    jobId,
    senderJid,
    messageId: key.id || null,
    remoteJid: key.remoteJid || null,
    fromMe: key.fromMe || false,
    instanceName: envelope.instance || null,

    originalPayload: root,
    originalBody: envelope,

    hasText,
    hasImage,
    hasPdf,

    text: textContent,
    imageCaption: resolvedImageCaption,

    image: hasImage ? imageMessage : null,
    pdf: hasPdf ? documentMessage : null
  }
}];

const allItems = $input.all();
const partialResults = [];

for (const item of allItems) {
  const d = item.json;

  if (d && d._hasData === true && d.payload) {
    partialResults.push({
      source: d.source || null,
      payload: d.payload
    });
    continue;
  }

  if (
    d &&
    (
      Object.prototype.hasOwnProperty.call(d, 'agency_id') ||
      Object.prototype.hasOwnProperty.call(d, 'services') ||
      Object.prototype.hasOwnProperty.call(d, 'steps') ||
      Object.prototype.hasOwnProperty.call(d, 'departures')
    )
  ) {
    partialResults.push({
      source: null,
      payload: d
    });
  }
}

const final = {
  title: null,
  agency_id: 1,
  countries: [],
  duration_nights: null,
  airline: null,
  description: null,
  itinerary: {},
  status: 'draft',
  photo_urls: [],
  is_global_pricing: false,
  global_pricing: null,
  lead_price: null,
  services: {
    included: [],
    excluded: []
  },
  steps: [],
  departures: []
};

function uniqueStrings(arr) {
  return [...new Set((arr || []).filter(v => v !== null && v !== undefined && v !== ''))];
}

function mergeHotels(existingHotels = [], incomingHotels = []) {
  const merged = [...existingHotels];

  for (const hotel of incomingHotels || []) {
    const idx = merged.findIndex(h =>
      (h.hotel_id ?? null) === (hotel.hotel_id ?? null) &&
      (h.custom_hotel_name ?? null) === (hotel.custom_hotel_name ?? null)
    );

    if (idx === -1) {
      merged.push(hotel);
    } else {
      const existing = merged[idx];
      merged[idx] = {
        hotel_id: existing.hotel_id ?? hotel.hotel_id ?? null,
        custom_hotel_name: existing.custom_hotel_name ?? hotel.custom_hotel_name ?? null,
        is_default: existing.is_default ?? hotel.is_default ?? false,
        pricing: {
          ...(existing.pricing || {}),
          ...(hotel.pricing || {})
        }
      };
    }
  }

  return merged;
}

function mergeSteps(existingSteps = [], incomingSteps = []) {
  const merged = [...existingSteps];

  for (const step of incomingSteps || []) {
    const idx = merged.findIndex(s =>
      (s.step_order ?? null) === (step.step_order ?? null)
    );

    if (idx === -1) {
      merged.push({
        city: step.city ?? null,
        step_order: step.step_order ?? null,
        duration_nights: step.duration_nights ?? null,
        hotels: Array.isArray(step.hotels) ? step.hotels : []
      });
    } else {
      const existing = merged[idx];
      merged[idx] = {
        city: existing.city ?? step.city ?? null,
        step_order: existing.step_order ?? step.step_order ?? null,
        duration_nights: existing.duration_nights ?? step.duration_nights ?? null,
        hotels: mergeHotels(existing.hotels || [], step.hotels || [])
      };
    }
  }

  return merged.sort((a, b) => (a.step_order ?? 9999) - (b.step_order ?? 9999));
}

function mergeDepartures(existingDeps = [], incomingDeps = []) {
  const merged = [...existingDeps];

  for (const dep of incomingDeps || []) {
    const idx = merged.findIndex(d =>
      (d.departure_city ?? null) === (dep.departure_city ?? null) &&
      (d.flight_departure_time ?? null) === (dep.flight_departure_time ?? null) &&
      (d.return_flight_departure_time ?? null) === (dep.return_flight_departure_time ?? null)
    );

    if (idx === -1) {
      merged.push(dep);
    } else {
      const existing = merged[idx];
      merged[idx] = {
        departure_city: existing.departure_city ?? dep.departure_city ?? null,
        stock: existing.stock ?? dep.stock ?? null,
        flight_departure_time: existing.flight_departure_time ?? dep.flight_departure_time ?? null,
        flight_arrival_time: existing.flight_arrival_time ?? dep.flight_arrival_time ?? null,
        return_flight_departure_time: existing.return_flight_departure_time ?? dep.return_flight_departure_time ?? null,
        return_flight_arrival_time: existing.return_flight_arrival_time ?? dep.return_flight_arrival_time ?? null
      };
    }
  }

  return merged;
}

// Priorité légère au texte
const sourcePriority = { text: 1, image: 2, pdf: 3, null: 99 };
partialResults.sort((a, b) => {
  const pa = sourcePriority[a.source ?? 'null'] ?? 99;
  const pb = sourcePriority[b.source ?? 'null'] ?? 99;
  return pa - pb;
});

for (const result of partialResults) {
  const p = result.payload || {};

  final.title = final.title ?? p.title ?? null;
  final.agency_id = final.agency_id ?? p.agency_id ?? 1;
  final.duration_nights = final.duration_nights ?? p.duration_nights ?? null;
  final.airline = final.airline ?? p.airline ?? null;
  final.description = final.description ?? p.description ?? null;
  final.lead_price = final.lead_price ?? p.lead_price ?? null;

  if (p.status && final.status === 'draft') {
    final.status = p.status;
  }

  if (p.is_global_pricing === true) {
    final.is_global_pricing = true;
    final.global_pricing = final.global_pricing ?? p.global_pricing ?? null;
  }

  final.countries = uniqueStrings([...(final.countries || []), ...(p.countries || [])]);
  final.photo_urls = uniqueStrings([...(final.photo_urls || []), ...(p.photo_urls || [])]);

  final.services.included = uniqueStrings([
    ...(final.services.included || []),
    ...((p.services && p.services.included) || [])
  ]);

  final.services.excluded = uniqueStrings([
    ...(final.services.excluded || []),
    ...((p.services && p.services.excluded) || [])
  ]);

  // texte légèrement prioritaire aussi sur itinerary
  final.itinerary = {
    ...(p.itinerary || {}),
    ...(final.itinerary || {})
  };

  final.steps = mergeSteps(final.steps, p.steps || []);
  final.departures = mergeDepartures(final.departures, p.departures || []);
}

return [{ json: final }];

const parseResult = $input.first().json;
const detectData = $('Detect Content & Generate JobId').first().json;

const jobId = detectData.jobId || 'unknown';

function createEmptyTour() {
  return {
    title: null,
    agency_id: 1,
    countries: [],
    duration_nights: null,
    airline: null,
    description: null,
    itinerary: {},
    status: 'draft',
    photo_urls: [],
    is_global_pricing: false,
    global_pricing: null,
    lead_price: null,
    services: {
      included: [],
      excluded: []
    },
    steps: [],
    departures: []
  };
}

function uniqueStrings(arr) {
  return [...new Set((arr || []).filter(v => typeof v === 'string' && v.trim() !== ''))];
}

function normalizeString(v) {
  return typeof v === 'string' && v.trim() !== '' ? v.trim() : null;
}

function normalizeNumber(v) {
  if (typeof v === 'number' && Number.isFinite(v)) return v;

  if (typeof v === 'string') {
    const cleaned = v
      .trim()
      .replace(/\s+/g, '')
      .replace(/,/g, '.')
      .replace(/[^\d.-]/g, '');

    if (!cleaned || cleaned === '.' || cleaned === '-' || cleaned === '-.') return null;

    const num = Number(cleaned);
    return Number.isFinite(num) ? num : null;
  }

  return null;
}

function titleCaseCity(v) {
  const s = normalizeString(v);
  if (!s) return null;

  return s
    .toLowerCase()
    .split(/\s+/)
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

function emptyGlobalPricingObject() {
  return {
    dbl: null,
    tpl: null,
    sgl: null,
    inf: null,
    chd_2_6: null,
    chd_5_11: null
  };
}

function extractJsonString(raw) {
  if (!raw || typeof raw !== 'string') return null;

  let text = raw.trim();

  text = text.replace(/^```json\s*/i, '');
  text = text.replace(/^```\s*/i, '');
  text = text.replace(/\s*```$/i, '').trim();

  if (text.startsWith('{') && text.endsWith('}')) {
    return text;
  }

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    return text.slice(firstBrace, lastBrace + 1);
  }

  return null;
}

function extractTextCandidates(value) {
  const results = [];

  function walk(node) {
    if (!node) return;

    if (typeof node === 'string') {
      results.push(node);
      return;
    }

    if (Array.isArray(node)) {
      for (const item of node) walk(item);
      return;
    }

    if (typeof node === 'object') {
      if (typeof node.text === 'string') results.push(node.text);

      if (Array.isArray(node.parts)) {
        for (const part of node.parts) {
          if (typeof part?.text === 'string') results.push(part.text);
        }
      }

      // walk common nested fields
      if (node.content) walk(node.content);
      if (node.output) walk(node.output);
      if (node.response) walk(node.response);
      if (node.message) walk(node.message);
      if (node.md) walk(node.md);
      if (node.markdown) walk(node.markdown);
      if (node.pages) walk(node.pages);
    }
  }

  walk(value);
  return results.filter(Boolean);
}

function normalizeGlobalPricing(value, isGlobalPricing) {
  if (!isGlobalPricing) return null;
  if (value == null) return emptyGlobalPricingObject();

  if (typeof value === 'number' || typeof value === 'string') {
    const singlePrice = normalizeNumber(value);
    if (singlePrice === null) return emptyGlobalPricingObject();

    return {
      dbl: singlePrice,
      tpl: null,
      sgl: null,
      inf: null,
      chd_2_6: null,
      chd_5_11: null
    };
  }

  if (typeof value !== 'object' || Array.isArray(value)) {
    return emptyGlobalPricingObject();
  }

  return {
    dbl: normalizeNumber(value.dbl ?? value.double),
    tpl: normalizeNumber(value.tpl ?? value.triple),
    sgl: normalizeNumber(value.sgl ?? value.single),
    inf: normalizeNumber(value.inf ?? value.infant),
    chd_2_6: normalizeNumber(value.chd_2_6 ?? value.child_2_6),
    chd_5_11: normalizeNumber(value.chd_5_11 ?? value.child_5_11)
  };
}

function normalizeHotelPricing(pricing) {
  return {
    single: normalizeNumber(pricing?.single ?? pricing?.sgl),
    double: normalizeNumber(pricing?.double ?? pricing?.dbl),
    triple: normalizeNumber(pricing?.triple ?? pricing?.tpl),
    quadruple: normalizeNumber(pricing?.quadruple ?? pricing?.quad ?? pricing?.qdr)
  };
}

function extractHotelMinPrice(hotel) {
  if (!hotel || typeof hotel !== 'object') return null;

  const p = hotel.pricing || {};

  const candidates = [
    normalizeNumber(p.quadruple),
    normalizeNumber(p.quad),
    normalizeNumber(p.qdr),
    normalizeNumber(p.triple),
    normalizeNumber(p.tpl),
    normalizeNumber(p.double),
    normalizeNumber(p.dbl),
    normalizeNumber(p.single),
    normalizeNumber(p.sgl),
    normalizeNumber(hotel.quadruple),
    normalizeNumber(hotel.quad),
    normalizeNumber(hotel.tpl),
    normalizeNumber(hotel.triple),
    normalizeNumber(hotel.dbl),
    normalizeNumber(hotel.double),
    normalizeNumber(hotel.sgl),
    normalizeNumber(hotel.single)
  ].filter(v => v !== null);

  return candidates.length ? Math.min(...candidates) : null;
}

function computeStepsDerivedLeadPrice(steps) {
  if (!Array.isArray(steps) || steps.length === 0) return null;

  let total = 0;

  for (const step of steps) {
    if (!step || !Array.isArray(step.hotels) || step.hotels.length === 0) {
      return null;
    }

    const stepPrices = step.hotels
      .map(h => extractHotelMinPrice(h))
      .filter(v => v !== null);

    if (stepPrices.length === 0) return null;

    total += Math.min(...stepPrices);
  }

  return total;
}

function computeGlobalPricingLeadPrice(globalPricing) {
  if (!globalPricing || typeof globalPricing !== 'object') return null;

  const adultCandidates = [
    normalizeNumber(globalPricing.tpl),
    normalizeNumber(globalPricing.dbl),
    normalizeNumber(globalPricing.sgl)
  ].filter(v => v !== null);

  return adultCandidates.length ? Math.min(...adultCandidates) : null;
}

// VERY IMPORTANT: collect text candidates robustly
const rawCandidates = extractTextCandidates(parseResult);

let parsed = null;
let usedRawCandidate = null;

for (const candidate of rawCandidates) {
  const jsonString = extractJsonString(candidate);
  if (!jsonString) continue;

  try {
    parsed = JSON.parse(jsonString);
    usedRawCandidate = candidate;
    break;
  } catch (error) {
    // continue
  }
}

if (!parsed) {
  return [{
    json: {
      extractionType: 'text',
      _hasData: false,
      source: 'text',
      jobId,
      debug_raw_candidates_count: rawCandidates.length,
      debug_first_candidate: rawCandidates[0] || null,
      payload: createEmptyTour()
    }
  }];
}

const payload = createEmptyTour();

payload.title = normalizeString(parsed.title);
payload.agency_id = 1;
payload.countries = uniqueStrings(Array.isArray(parsed.countries) ? parsed.countries : []);
payload.duration_nights = normalizeNumber(parsed.duration_nights);
payload.airline = normalizeString(parsed.airline);
payload.description = normalizeString(parsed.description);
payload.status = 'draft';

payload.photo_urls = Array.isArray(parsed.photo_urls)
  ? parsed.photo_urls.filter(v => typeof v === 'string' && v.trim() !== '')
  : [];

payload.is_global_pricing = parsed.is_global_pricing === true;
payload.global_pricing = normalizeGlobalPricing(parsed.global_pricing, payload.is_global_pricing);
payload.lead_price = normalizeNumber(parsed.lead_price);

payload.services = {
  included: uniqueStrings(parsed?.services?.included),
  excluded: uniqueStrings(parsed?.services?.excluded)
};

if (parsed.itinerary && typeof parsed.itinerary === 'object' && !Array.isArray(parsed.itinerary)) {
  const keys = Object.keys(parsed.itinerary);
  const alreadyDayFormat = keys.every(k => /^day_\d+$/i.test(k));

  if (alreadyDayFormat) {
    const normalizedItinerary = {};
    for (const [key, value] of Object.entries(parsed.itinerary)) {
      if (typeof value === 'string' && value.trim() !== '') {
        normalizedItinerary[key] = value.trim();
      }
    }
    payload.itinerary = normalizedItinerary;
  } else {
    let i = 1;
    const normalizedItinerary = {};
    for (const [key, value] of Object.entries(parsed.itinerary)) {
      if (typeof value === 'string' && value.trim() !== '') {
        normalizedItinerary[`day_${i}`] = value.trim();
        i++;
      } else if (value && typeof value === 'object') {
        const parts = [];
        if (key) parts.push(titleCaseCity(key));
        if (value.hotel) parts.push(`hôtel: ${value.hotel}`);
        if (value.nights) parts.push(`${value.nights} nuits`);
        if (parts.length > 0) {
          normalizedItinerary[`day_${i}`] = parts.join(', ');
          i++;
        }
      }
    }
    payload.itinerary = normalizedItinerary;
  }
}

if (Array.isArray(parsed.steps) && parsed.steps.length > 0) {
  payload.steps = parsed.steps
    .map((step, index) => ({
      city: titleCaseCity(step.city),
      step_order: typeof step.step_order === 'number' ? step.step_order : index + 1,
      duration_nights: normalizeNumber(step.duration_nights),
      hotels: Array.isArray(step.hotels)
        ? step.hotels.map(h => ({
            hotel_id: h.hotel_id ?? null,
            custom_hotel_name: normalizeString(h.custom_hotel_name ?? h.hotel_name ?? h.name),
            is_default: h.is_default === true,
            pricing: normalizeHotelPricing(h.pricing)
          }))
        : []
    }))
    .filter(step => step.city !== null || step.hotels.length > 0);
}

payload.steps = payload.steps
  .sort((a, b) => (a.step_order ?? 9999) - (b.step_order ?? 9999))
  .map((step, index) => ({
    ...step,
    step_order: index + 1
  }));

const stepDurationValues = payload.steps
  .map(step => normalizeNumber(step.duration_nights))
  .filter(v => v !== null);

if (payload.steps.length > 0 && stepDurationValues.length === payload.steps.length) {
  payload.duration_nights = stepDurationValues.reduce((sum, v) => sum + v, 0);
}

if (Array.isArray(parsed.departures)) {
  payload.departures = parsed.departures
    .map(dep => {
      const explicitDepartureCity = normalizeString(dep.departure_city);
      const stock = normalizeNumber(dep.stock);
      const flightDepartureTime = normalizeString(dep.flight_departure_time);
      const flightArrivalTime = normalizeString(dep.flight_arrival_time);
      const returnFlightDepartureTime = normalizeString(dep.return_flight_departure_time);
      const returnFlightArrivalTime = normalizeString(dep.return_flight_arrival_time);

      const hasMeaningfulData =
        explicitDepartureCity !== null ||
        stock !== null ||
        flightDepartureTime !== null ||
        flightArrivalTime !== null ||
        returnFlightDepartureTime !== null ||
        returnFlightArrivalTime !== null;

      if (!hasMeaningfulData) return null;

      return {
        departure_city: explicitDepartureCity || 'Alger',
        stock,
        flight_departure_time: flightDepartureTime,
        flight_arrival_time: flightArrivalTime,
        return_flight_departure_time: returnFlightDepartureTime,
        return_flight_arrival_time: returnFlightArrivalTime
      };
    })
    .filter(Boolean);
}

if (!payload.is_global_pricing) {
  payload.global_pricing = null;
} else {
  payload.global_pricing = payload.global_pricing || emptyGlobalPricingObject();
}

const explicitLeadPrice = normalizeNumber(parsed.lead_price);
const globalPricingLeadPrice = computeGlobalPricingLeadPrice(payload.global_pricing);
const stepsDerivedLeadPrice = computeStepsDerivedLeadPrice(parsed.steps);

const leadPriceCandidates = [
  explicitLeadPrice,
  globalPricingLeadPrice,
  stepsDerivedLeadPrice
].filter(v => v !== null);

payload.lead_price = leadPriceCandidates.length > 0
  ? Math.min(...leadPriceCandidates)
  : null;

return [{
  json: {
    extractionType: 'text',
    _hasData: true,
    source: 'text',
    jobId,
    debug_used_candidate_preview: usedRawCandidate ? usedRawCandidate.slice(0, 300) : null,
    payload
  }
}];

const parseResult = $input.first().json;
const detectData = $('Detect Content & Generate JobId').first().json;

const jobId = detectData.jobId || 'unknown';

function createEmptyTour() {
  return {
    title: null,
    agency_id: 1,
    countries: [],
    duration_nights: null,
    airline: null,
    description: null,
    itinerary: {},
    status: 'draft',
    photo_urls: [],
    is_global_pricing: false,
    global_pricing: null,
    lead_price: null,
    services: {
      included: [],
      excluded: []
    },
    steps: [],
    departures: []
  };
}

function uniqueStrings(arr) {
  return [...new Set((arr || []).filter(v => typeof v === 'string' && v.trim() !== ''))];
}

function normalizeString(v) {
  return typeof v === 'string' && v.trim() !== '' ? v.trim() : null;
}

function normalizeNumber(v) {
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  if (typeof v === 'string') {
    const cleaned = v.replace(/[^\d.,-]/g, '').replace(',', '.');
    const parsed = Number(cleaned);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
}

function titleCaseCity(v) {
  const s = normalizeString(v);
  if (!s) return null;
  return s.charAt(0).toUpperCase() + s.slice(1);
}

function extractJsonString(raw) {
  if (!raw || typeof raw !== 'string') return null;

  let text = raw.trim();

  text = text.replace(/^```json\s*/i, '');
  text = text.replace(/^```\s*/i, '');
  text = text.replace(/\s*```$/i, '').trim();

  if (text.startsWith('{') && text.endsWith('}')) {
    return text;
  }

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    return text.slice(firstBrace, lastBrace + 1);
  }

  return null;
}

function parseIsoDate(value) {
  if (!value || typeof value !== 'string') return null;
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function diffNights(start, end) {
  const startDate = parseIsoDate(start);
  const endDate = parseIsoDate(end);
  if (!startDate || !endDate) return null;

  const msPerDay = 1000 * 60 * 60 * 24;
  const utcStart = Date.UTC(
    startDate.getUTCFullYear(),
    startDate.getUTCMonth(),
    startDate.getUTCDate()
  );
  const utcEnd = Date.UTC(
    endDate.getUTCFullYear(),
    endDate.getUTCMonth(),
    endDate.getUTCDate()
  );

  const diff = Math.round((utcEnd - utcStart) / msPerDay);
  return diff >= 0 ? diff : null;
}

// Llama Parse can return markdown/text/pages
const rawCandidates = [
  parseResult?.md,
  parseResult?.markdown,
  parseResult?.text,
  ...(Array.isArray(parseResult?.pages)
    ? parseResult.pages.flatMap(p => [p?.md, p?.markdown, p?.text].filter(Boolean))
    : [])
].filter(Boolean);

let parsed = null;

for (const candidate of rawCandidates) {
  const jsonString = extractJsonString(candidate);
  if (!jsonString) continue;

  try {
    parsed = JSON.parse(jsonString);
    break;
  } catch (error) {
    // continue
  }
}

if (!parsed) {
  return [{
    json: {
      extractionType: 'pdf',
      _hasData: false,
      source: 'pdf',
      jobId,
      payload: createEmptyTour()
    }
  }];
}

const payload = createEmptyTour();

